import ARROW_IMG from './assets/arrowz.jpg';
// DoctorLogin.jsx
// Purpose: Doctor authentication UI. This component uses demo default
// credentials for local development; remove defaults and require real
// credentials in production. Tokens are stored in sessionStorage here —
// prefer secure, short-lived tokens and server-side session validation.
import React, { useState } from 'react';
import axios from 'axios';
import { API_URL } from './apiConfig';
import AppHeader from './AppHeader';
import AdRotator from './AdRotator';


const DEFAULT_NAME = 'DrAdmin';
const DEFAULT_PASSWORD = 'Doctor@1122';

const BG_IMG    = "data:image/jpeg;base64,";
const LOGO_IMG  = "data:image/jpeg;base64,";
const BANNER_IMG= "data:image/jpeg;base64,";
const DAPP_IMG  = "data:image/png;base64,";

const BOTTOM_LEFT_IMG = "data:image/png;base64,";

const DoctorLogin = ({ onLoginSuccess, onNavigate }) => {
  const [isLoading, setIsLoading]     = useState(false);
  const [error, setError]             = useState('');
  const [success, setSuccess]         = useState('');
  const [infoMessage, setInfoMessage] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loginForm, setLoginForm]     = useState({ name: '', password: '' });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setLoginForm(prev => ({ ...prev, [name]: value }));
    setError('');
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    setError(''); setSuccess(''); setIsLoading(true);
    try {
      const response = await axios.post(`${API_URL}/api/doctor/login`, {
        name: loginForm.name.trim(),
        password: loginForm.password
      });
      sessionStorage.setItem('authToken', response.data.access_token);
      sessionStorage.setItem('userRole', 'doctor');
      sessionStorage.setItem('doctorName', response.data.doctor.name);
      sessionStorage.setItem('doctorEmail', response.data.doctor.email);
      setSuccess('✓ Login successful! Redirecting...');
      setTimeout(() => onLoginSuccess(response.data.access_token, response.data.doctor), 1500);
    } catch (err) {
      const detail = err.response?.data?.detail;
      if (err.response?.status === 401)      setError(typeof detail === 'string' ? detail : 'Invalid credentials.');
      else if (err.response?.status === 403) setError((typeof detail === 'object' ? detail.message : detail) || 'Account not active.');
      else if (err.response?.status === 404) setError('Doctor account not found.');
      else                                   setError('Login failed. Please try again.');
    } finally { setIsLoading(false); }
  };

  return (
    <div style={{ fontFamily: "'Myriad Pro', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif" }}>
      <style>{`
        * { margin: 0; padding: 0; box-sizing: border-box; }
        html, body, #root { min-height: 100%; width: 100%; overflow-x: hidden; }

        .login-wrapper {
          min-height: 100vh;
          width: 100%;
          display: flex;
          flex-direction: column;
          overflow-x: hidden;
          overflow-y: auto;
          background: #ffffff;
          position: relative;
        }

        /* ── HEADER ── */
        .header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          padding: 14px 44px;
          background: #fff;
          flex-shrink: 0;
          z-index: 20;
        }

        /* ── HERO (background image section) ── */
        .hero {
          position: relative;
          height: 300px;
          width: 100%;
          overflow: visible;
          flex-shrink: 0;
        }

        .hero-bg {
          position: absolute;
          inset: 0;
          width: 100%;
          height: 100%;
          object-fit: cover;
          object-position: center center;
          display: block;
        }

        /* ── LOGIN CARD — straddles hero / content boundary ── */
        .login-card {
          position: absolute;
          right: 60px;
          bottom: -130px;
          background: #ffffff;
          padding: 22px 28px;
          width: 350px;
          box-shadow: 0 15px 50px rgba(0,0,0,0.15);
          border-radius: 24px;
          z-index: 30;
        }

        .login-title {
          color: #8b5cf6;
          font-size: 22px;
          font-weight: 600;
          margin-bottom: 16px;
          font-family: 'Myriad Pro', sans-serif;
        }

        .form-group { margin-bottom: 13px; }

        .form-label {
          display: block;
          font-size: 12px;
          color: #666;
          margin-bottom: 5px;
        }

        .form-input {
          width: 100%;
          padding: 9px 10px;
          border: 1px solid #ddd;
          font-size: 14px;
          outline: none;
          border-radius: 6px;
          font-family: 'Myriad Pro', sans-serif;
          background: #fff;
        }

        .form-input:focus {
          border-color: #8b5cf6;
          box-shadow: 0 0 0 2px rgba(139,92,246,0.12);
        }

        .password-field { position: relative; }
        .password-field .form-input { padding-right: 36px; }

        .password-toggle {
          position: absolute;
          right: 10px;
          top: 50%;
          transform: translateY(-50%);
          background: none;
          border: none;
          cursor: pointer;
          color: #888;
          font-size: 17px;
          padding: 4px;
          display: flex;
          align-items: center;
        }
        .password-toggle:hover { color: #8b5cf6; }

        .submit-btn {
          width: 100%;
          padding: 11px;
          background: linear-gradient(to right, #8b5cf6, #d946ef);
          color: white;
          border: none;
          font-size: 14px;
          font-weight: 500;
          cursor: pointer;
          margin-top: 10px;
          border-radius: 6px;
          transition: opacity 0.2s;
          font-family: 'Myriad Pro', sans-serif;
        }
        .submit-btn:hover { opacity: 0.9; }
        .submit-btn:disabled { opacity: 0.6; cursor: not-allowed; }

        .signup-link {
          display: block;
          text-align: right;
          margin-top: 12px;
          font-size: 12px;
          color: #666;
        }
        .signup-link a { color: #8b5cf6; text-decoration: none; cursor: pointer; }
        .signup-link a:hover { text-decoration: underline; }

        /* ── CONTENT (white strip below hero) ── */
        .content {
          padding: 20px 44px 20px;
          display: flex;
          align-items: flex-start;
          justify-content: flex-start;
          background: white;
          position: relative;
          z-index: 10;
          min-height: 240px;
        }

        .welcome-text {
          font-size: 14px;
          color: #333;
          max-width: 500px;
          line-height: 1.5;
          font-family: 'Myriad Pro', sans-serif;
        }

        .arrow-wrap {
          position: absolute;
          right: 440px;
          top: 20px;
          z-index: 31;
          display: flex;
          align-items: center;
          justify-content: center;
          overflow: hidden;
        }

        .dapp-logo-content {
          position: absolute;
          right: 520px;
          bottom: 10px;
          width: 80px;
          height: auto;
          z-index: 11;
        }

        .footer {
          padding: 8px 44px;
          text-align: center;
          background: white;
          flex-shrink: 0;
          z-index: 10;
        }

        .footer-links {
          display: flex;
          justify-content: center;
          gap: 10px;
          font-size: 12px;
          color: #666;
        }
        .footer-links a { color: #666; text-decoration: none; }
        .footer-links a:hover { color: #8b5cf6; }
        .footer-links span { color: #ccc; }

        .error-message {
          color: #dc2626; font-size: 12px; padding: 8px;
          background: #fee2e2; border: 1px solid #fecaca;
          border-radius: 4px; margin-bottom: 10px;
        }
        .success-message {
          color: #059669; font-size: 12px; padding: 8px;
          background: #d1fae5; border: 1px solid #a7f3d0;
          border-radius: 4px; margin-bottom: 10px;
        }

        .info-message {
          color: #92400e; font-size: 12px; padding: 8px;
          background: #fef3c7; border: 1px solid #fcd34d;
          border-radius: 4px; margin-bottom: 10px;
          white-space: pre-line;
        }

        .bottom-left-decoration {
          position: fixed;
          bottom: -15px;
          left: 0;
          width: 120px;
          height: auto;
          z-index: 100;
          pointer-events: none;
        }

        @media (max-width: 768px) {
          .header { padding: 14px 20px; flex-direction: column; align-items: stretch; gap: 10px; }
          .hero { height: 280px; }
          .login-card {
            position: absolute;
            left: 50%;
            transform: translateX(-50%);
            bottom: -110px;
            right: auto;
            top: auto;
            margin-top: 0;
            width: min(calc(100% - 32px), 320px);
            padding: 16px;
            box-shadow: 0 18px 35px rgba(0,0,0,0.14);
            border-radius: 18px;
            z-index: 40;
          }
          .content {
            padding: 140px 18px 26px;
            flex-direction: column;
            align-items: flex-start;
          }
          .arrow-wrap {
            position: relative;
            right: auto;
            top: auto;
            margin: 30px auto 0;
            display: flex;
            justify-content: center;
            width: 100%;
          }
          .dapp-logo-content { display: none; }
          .bottom-left-decoration { position: absolute; bottom: -10px; left: 0; width: 100px; height: auto; z-index: 50; opacity: 1; }
          .footer { padding: 14px 18px; }
          .login-title { font-size: 18px; margin-bottom: 14px; }
          .form-group { margin-bottom: 11px; }
          .form-input { font-size: 14px; padding: 8px 9px; }
          .footer-links { flex-wrap: wrap; gap: 8px; }
        }

        @media (max-width: 480px) {
          .hero { height: 240px; }
          .login-card { bottom: -92px; width: min(calc(100% - 24px), 285px); padding: 14px; border-radius: 16px; font-size: 13px; }
          .content { padding: 120px 14px 20px; }
          .header { padding: 8px 10px; }
          .footer { padding: 10px 12px; font-size: 11px; }
          .login-title { font-size: 15px; margin-bottom: 11px; }
          .form-label { font-size: 11px; margin-bottom: 4px; }
          .form-input { font-size: 13px; padding: 7px 8px; }
          .submit-btn { padding: 9px; font-size: 12px; margin-top: 8px; }
          .signup-link { font-size: 11px; }
          .bottom-left-decoration { position: absolute; width: 80px; bottom: -8px; z-index: 50; opacity: 1; }
        }
      `}</style>

      <div className="login-wrapper">

        <AppHeader />

        {/* ── HERO — background image only, no overlays ── */}
        <section className="hero">
          <img src={BG_IMG} alt="background" className="hero-bg" />

          {/* Login card — half inside hero, half below */}
          <div className="login-card">
            <h2 className="login-title">Login</h2>

            {error   && <div className="error-message">{error}</div>}
            {success && <div className="success-message">{success}</div>}
            {infoMessage && <div className="info-message">{infoMessage}</div>}

            <form onSubmit={handleLogin}>
              <div className="form-group">
                <label className="form-label">Email address</label>
                <input
                  type="text" name="name"
                  value={loginForm.name} onChange={handleChange}
                  className="form-input" placeholder="Dr. Username" required
                />
              </div>
              <div className="form-group">
                <label className="form-label">Password</label>
                <div className="password-field">
                  <input
                    type={showPassword ? "text" : "password"} name="password"
                    value={loginForm.password} onChange={handleChange}
                    className="form-input" placeholder="Password" required
                  />
                  <button type="button" className="password-toggle"
                    onClick={() => setShowPassword(!showPassword)}
                    title={showPassword ? "Hide password" : "Show password"}>
                    {showPassword ? "👁️" : "👁️‍🗨️"}
                  </button>
                </div>
              </div>
              <button type="submit" className="submit-btn" disabled={isLoading}>
                {isLoading ? 'Authenticating...' : 'Submit'}
              </button>
            </form>

            <div className="signup-link">
              Not Registered? <a onClick={() => {
                const message = 'Sign up disabled temporarily\nPlease contact the System Administrator';
                setInfoMessage(message);
                window.alert(message);
              }}>Sign Up</a>
            </div>
          </div>
        </section>

        {/* ── CONTENT (white strip) ── */}
        <section className="content">
          <p className="welcome-text">
            Welcome to DiabAssist, the AI-Powered, evidence-based, real-time,
            deep-learning enabled, clinical assistance tool.
          </p>

          {/* Arrow (Purple Logo) */}
          <div className="arrow-wrap" style={{ display: 'flex', justifyContent: 'center' }}>
            <img src={ARROW_IMG} alt=""
              style={{ 
                height: '200px', 
                width: 'auto', 
                display: 'block',
                background: 'transparent',
                objectFit: 'contain'
              }} />
          </div>

          {/* Static Banner */}
          <AdRotator page="login" />
        </section>

        {/* ── FOOTER ── */}
        <footer className="footer">
          <div className="footer-links">
            <a href="#" onClick={(e) => { e.preventDefault(); onNavigate('privacy'); }}>Privacy Statement</a>
            <span>•</span>
            <a href="#" onClick={(e) => { e.preventDefault(); onNavigate('terms'); }}>Terms and Conditions</a>
            <span>•</span>
            <a href="#" onClick={(e) => { e.preventDefault(); onNavigate('helpline'); }}>Helpline</a>
          </div>
          <div style={{ color: '#374151', fontSize: '12px', fontWeight: 'bold', marginTop: '8px' }}>
            Powered by Elements Interactive
          </div>
        </footer>

        <img src={BOTTOM_LEFT_IMG} alt="" className="bottom-left-decoration" />
      </div>
    </div>
  );
};

export { BG_IMG };
export default DoctorLogin;
